import type { DependencyList, SetStateAction } from 'react';
import { useStableCallback } from '#registry/default/hooks/use-stable-callback.ts';
import { useStateWithDeps } from '#registry/default/hooks/use-state-with-deps.ts';

export type ControlValue = {} | null;

export type ControlOnChangeFn<T, TCtx = void> = (
  value: SetStateAction<T>,
  ctx?: TCtx
) => void | unknown | Promise<unknown>;

export type ControlProps<T extends ControlValue = ControlValue, TCtx = void> = {
  onChange?: NoInfer<ControlOnChangeFn<T, TCtx>>;
  /** Resets the uncontrolled value when dependencies change */
  deps?: DependencyList;

  value?: T;
  defaultValue?: T;
  finalValue?: T;
};

/**
 * Working with two-way binding in React can be tricky.
 * React has a concept of controlled and uncontrolled components.
 * Ideally, our components should also be able to work in both modes.
 * This hook helps to work with both scenarios in a consistent way.
 */
export function useControl<T extends ControlValue, TCtx = void>({
  value,
  defaultValue,
  finalValue,
  deps,
  onChange,
}: ControlProps<T, TCtx>) {
  const isControlled = value !== undefined;
  deps ??= [isControlled];
  const [state, setState] = useStateWithDeps<T>(defaultValue === undefined ? finalValue! : defaultValue, deps);

  const handleChange = useStableCallback((val: SetStateAction<T>, ctx?: TCtx) => {
    if (!isControlled) setState(val);
    onChange?.(val, ctx);
  });

  if (isControlled) return [value as T, handleChange] as const;
  return [state!, handleChange] as const;
}
